const SELECTORS = {
    expandCell: "dx-command-expand"
};
export class GroupRowModel {
    constructor(root) {
        this.root = root
    }
    getElement() {
        return this.root
    }
    getExpandCell() {
        const row = this.getElement();
        return row.querySelector(`.${SELECTORS.expandCell}`)
    }
}
